package org.apache.commons.fileupload;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertTrue;

import java.util.Map;
import org.junit.Test;

/**
 * Unit tests for {@link ParameterParser#parse2(char[], char)}.
 */
public class ParameterParser2Test {
    private final ParameterParser parser = new ParameterParser();

    @Test
    public void testParse2_NullArray() {
        Map<String, String> params = parser.parse2((char[]) null, ';');
        assertTrue("Expected empty map for null input", params.isEmpty());
    }

    @Test
    public void testParse2_EmptyArray() {
        Map<String, String> params = parser.parse2(new char[0], ';');
        assertTrue("Expected empty map for empty input", params.isEmpty());
    }

    @Test
    public void testParse2_SimplePairs() {
        char[] input = "a=b;c=d".toCharArray();
        Map<String, String> params = parser.parse2(input, ';');
        assertEquals("b", params.get("a"));
        assertEquals("d", params.get("c"));
        assertEquals(2, params.size());
    }

    @Test
    public void testParse2_QuotedValue() {
        char[] input = "x=\"hello;world\";y=42".toCharArray();
        Map<String, String> params = parser.parse2(input, ';');
        assertEquals("hello;world", params.get("x"));
        assertEquals("42", params.get("y"));
        assertEquals(2, params.size());
    }
}

package org.apache.commons.fileupload;

import static org.junit.Assert.*;
import org.junit.Test;
import java.util.Map;

/**
 * Unit tests for ParameterParser.parse0 method.
 */
public class ParameterParserTest {

    @Test
    public void testEmptySeparatorsEmpty() {
        ParameterParser parser = new ParameterParser();
        Map<String, String> result = parser.parse0("a=1;b=2", new char[]{});
        assertTrue(result.isEmpty());
    }

    @Test
    public void testEmptySeparatorsNull() {
        ParameterParser parser = new ParameterParser();
        Map<String, String> result = parser.parse0("a=1;b=2", null);
        assertTrue(result.isEmpty());
    }

    @Test
    public void testStrNull() {
        ParameterParser parser = new ParameterParser();
        Map<String, String> result = parser.parse0(null, new char[]{';'});
        assertTrue(result.isEmpty());
    }

    @Test
    public void testSimple() {
        ParameterParser parser = new ParameterParser();
        Map<String, String> result = parser.parse0("a=1;b=2", new char[]{';'});
        assertEquals(2, result.size());
        assertEquals("1", result.get("a"));
        assertEquals("2", result.get("b"));
    }

    @Test
    public void testMultipleSeparators() {
        ParameterParser parser = new ParameterParser();
        Map<String, String> result = parser.parse0("a=1,b=2;c=3", new char[]{',',';'});
        assertEquals(2, result.size());
        assertEquals("1", result.get("a"));
        assertEquals("2;c=3", result.get("b"));
    }

    @Test
    public void testQuotedValue() {
        ParameterParser parser = new ParameterParser();
        Map<String, String> result = parser.parse0("param=\"a;b\";other=2", new char[]{';'});
        assertEquals(2, result.size());
        assertEquals("a;b", result.get("param"));
        assertEquals("2", result.get("other"));
    }
}

