from org.apache.commons.fileupload.ParameterParser import ParameterParser

class TestParameterParser(unittest.TestCase):
    def test_empty_separators_empty(self):
        parser = ParameterParser()
        self.assertEqual(parser.parse0("a=1;b=2", []), {})

    def test_empty_separators_none(self):
        parser = ParameterParser()
        self.assertEqual(parser.parse0("a=1;b=2", None), {})

    def test_str_none(self):
        parser = ParameterParser()
        self.assertEqual(parser.parse0(None, [';']), {})

    def test_simple(self):
        parser = ParameterParser()
        self.assertEqual(parser.parse0("a=1;b=2", [';']), {'a': '1', 'b': '2'})

    def test_multiple_separators(self):
        parser = ParameterParser()
        self.assertEqual(
            parser.parse0("a=1,b=2;c=3", [',', ';']),
            {'a': '1', 'b': '2;c=3'}
        )

    def test_quoted_value(self):
        parser = ParameterParser()
        self.assertEqual(
            parser.parse0('param="a;b";other=2', [';']),
            {'param': 'a;b', 'other': '2'}
        )

if __name__ == '__main__':
    unittest.main()

