package org.apache.commons.fileupload;

import static org.junit.Assert.*;
import org.junit.Before;
import org.junit.Test;
import java.lang.reflect.Method;

public class ParameterParserIsOneOfTest {
    private Method isOneOfMethod;

    @Before
    public void setUp() throws Exception {
        isOneOfMethod = ParameterParser.class.getDeclaredMethod("isOneOf", char.class, char[].class);
        isOneOfMethod.setAccessible(true);
    }

    @Test
    public void testEmptyArray() throws Exception {
        ParameterParser parser = new ParameterParser();
        assertFalse((Boolean) isOneOfMethod.invoke(parser, 'a', new char[0]));
    }

    @Test
    public void testSingleMatch() throws Exception {
        ParameterParser parser = new ParameterParser();
        assertTrue((Boolean) isOneOfMethod.invoke(parser, 'a', new char[] {'a'}));
    }

    @Test
    public void testSingleNoMatch() throws Exception {
        ParameterParser parser = new ParameterParser();
        assertFalse((Boolean) isOneOfMethod.invoke(parser, 'a', new char[] {'b'}));
    }

    @Test
    public void testMultiple() throws Exception {
        ParameterParser parser = new ParameterParser();
        char[] arr = new char[] {'x', 'y', 'z'};
        assertTrue((Boolean) isOneOfMethod.invoke(parser, 'y', arr));
        assertFalse((Boolean) isOneOfMethod.invoke(parser, 'a', arr));
    }
}

package org.apache.commons.fileupload;

import static org.junit.Assert.*;
import org.junit.Test;

import java.io.ByteArrayInputStream;
import java.io.InputStream;
import java.lang.reflect.Field;

public class MultipartStreamConstructorTest {

    @Test(expected = IllegalArgumentException.class)
    public void testNullBoundary() throws Exception {
        InputStream in = new ByteArrayInputStream(new byte[] {});
        new MultipartStream(in, null, 10, null);
    }

    @Test(expected = IllegalArgumentException.class)
    public void testSmallBufferSize() throws Exception {
        byte[] boundary = new byte[] {1, 2, 3};
        InputStream in = new ByteArrayInputStream(new byte[] {});
        int boundaryLength = boundary.length + MultipartStream.BOUNDARY_PREFIX.length;
        // bufSize less than boundaryLength + 1 should trigger exception
        new MultipartStream(in, boundary, boundaryLength, null);
    }

    @Test
    public void testValidInitialization() throws Exception {
        byte[] boundary = new byte[] {1, 2, 3};
        ByteArrayInputStream in = new ByteArrayInputStream(new byte[] {10, 20, 30});
        MultipartStream ms = new MultipartStream(in, boundary, 20, null);

        Field fBoundaryLength = MultipartStream.class.getDeclaredField("boundaryLength");
        fBoundaryLength.setAccessible(true);
        int bl = fBoundaryLength.getInt(ms);
        assertEquals(boundary.length + MultipartStream.BOUNDARY_PREFIX.length, bl);

        Field fBufSize = MultipartStream.class.getDeclaredField("bufSize");
        fBufSize.setAccessible(true);
        int bs = fBufSize.getInt(ms);
        assertEquals(Math.max(20, bl * 2), bs);

        Field fBuffer = MultipartStream.class.getDeclaredField("buffer");
        fBuffer.setAccessible(true);
        byte[] buf = (byte[]) fBuffer.get(ms);
        assertEquals(bs, buf.length);

        Field fBoundary = MultipartStream.class.getDeclaredField("boundary");
        fBoundary.setAccessible(true);
        byte[] bArr = (byte[]) fBoundary.get(ms);
        byte[] expected = new byte[bl];
        System.arraycopy(MultipartStream.BOUNDARY_PREFIX, 0, expected, 0, MultipartStream.BOUNDARY_PREFIX.length);
        System.arraycopy(boundary, 0, expected, MultipartStream.BOUNDARY_PREFIX.length, boundary.length);
        assertArrayEquals(expected, bArr);

        Field fBoundaryTable = MultipartStream.class.getDeclaredField("boundaryTable");
        fBoundaryTable.setAccessible(true);
        int[] table = (int[]) fBoundaryTable.get(ms);
        assertEquals(bl + 1, table.length);

        Field fKeepRegion = MultipartStream.class.getDeclaredField("keepRegion");
        fKeepRegion.setAccessible(true);
        int kr = fKeepRegion.getInt(ms);
        assertEquals(bl, kr);

        Field fHead = MultipartStream.class.getDeclaredField("head");
        fHead.setAccessible(true);
        int head = fHead.getInt(ms);
        assertEquals(0, head);

        Field fTail = MultipartStream.class.getDeclaredField("tail");
        fTail.setAccessible(true);
        int tail = fTail.getInt(ms);
        assertEquals(0, tail);

        Field fNotifier = MultipartStream.class.getDeclaredField("notifier");
        fNotifier.setAccessible(true);
        Object notifier = fNotifier.get(ms);
        assertNull(notifier);
    }
}
